settings.custom_css:
selector .wdk_dropdown_tree > .btn-group {
  width: 100%;
  display: flex;
  height: 46px;
  overflow: hidden;
  border-color: transparent;
  background: white;
}

selector .wdk-search.layout_inline .wdk-row .wdk-col {
  position: relative;
}

selector .wdk-search.layout_inline .wdk-row div.wdk-col.wdk-field:first-child:after {
content: "";
  position: absolute;
  right: 0;
  font-weight: 200;
  height: 31px;
  width: 1px;
  background: #C2C2C2;
  top: 50%;
  margin-top: -15px;
}
